SELECT COUNT(DISTINCT chapter_number) AS chapters_read,
SUM(duration_seconds) AS total_time,
AVG(reading_speed_wpm) AS avg_speed
FROM reading_activity_log
WHERE user_id = #{userId}
AND book_id = #{bookId}

SELECT AVG(reading_speed_wpm)::INTEGER
FROM reading_activity_log
WHERE user_id = #{userId}
AND book_id = #{bookId}
AND reading_speed_wpm IS NOT NULL
AND reading_speed_wpm > 0
